// 极简版认证路由 - 修复版：持久化用户到 data/users.json
import express from 'express';
import jwt from 'jsonwebtoken';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = path.resolve(__dirname, '../..');
const DATA_DIR = path.join(PROJECT_ROOT, 'data');
const USERS_FILE = path.join(DATA_DIR, 'users.json');
const router = express.Router();

// 确保数据目录和文件存在
if (!fs.existsSync(DATA_DIR)) {
  fs.mkdirSync(DATA_DIR, { recursive: true });
}
if (!fs.existsSync(USERS_FILE)) {
  fs.writeFileSync(USERS_FILE, JSON.stringify([]));
}

// JWT密钥 - 必须与 middleware/auth.js 一致
const JWT_SECRET = process.env.JWT_SECRET || 'claw-default-secret-key-for-development-only-32chars';

// 读写 users.json
function getUsers() {
  try {
    return JSON.parse(fs.readFileSync(USERS_FILE, 'utf8'));
  } catch {
    return [];
  }
}

function saveUsers(users) {
  try {
    fs.writeFileSync(USERS_FILE, JSON.stringify(users, null, 2));
    return true;
  } catch (err) {
    console.error('保存用户失败:', err);
    return false;
  }
}

function findUserByEmail(email) {
  return getUsers().find(u => u.email === email);
}

function findUserById(id) {
  return getUsers().find(u => u.id === id);
}

function createUser(user) {
  const users = getUsers();
  users.push(user);
  return saveUsers(users) ? user : null;
}

// 生成唯一用户ID
function generateUserId() {
  return 'id_' + Date.now().toString(36) + '_' + Math.random().toString(36).substring(2, 9);
}

// 预定义管理员（用于系统内置账号）
const BUILTIN_USERS = {
  'admin@claw.com': {
    id: 'user-admin-001',
    name: '管理员',
    role: 'admin',
    plan: 'enterprise'
  },
  'user@claw.com': {
    id: 'user-demo-001',
    name: '演示用户',
    role: 'user',
    plan: 'premium'
  },
  'test@claw.com': {
    id: 'user-test-001',
    name: '测试用户',
    role: 'user',
    plan: 'basic'
  }
};

// POST /api/auth/login - 用户登录
router.post('/login', (req, res) => {
  try {
    const { email, password } = req.body;

    if (!email || !password) {
      return res.status(400).json({
        success: false,
        error: '邮箱和密码不能为空'
      });
    }

    console.log(`[认证] 登录请求: ${email}`);

    // 先从 JSON 查，再查内置
    let user = findUserByEmail(email);

    // 内置账号（用于演示）
    if (!user && BUILTIN_USERS[email]) {
      user = { ...BUILTIN_USERS[email], email };
    }

    // 如果 JSON 中没有，创建新用户并存入文件
    if (!user) {
      const userId = generateUserId();
      user = {
        id: userId,
        email,
        name: email.split('@')[0] || '用户',
        role: email.includes('admin') ? 'admin' : 'user',
        plan: 'free',
        createdAt: new Date().toISOString()
      };
      const saved = createUser(user);
      if (!saved) {
        return res.status(500).json({ success: false, error: '用户创建失败' });
      }
      console.log(`[认证] 新用户注册并登录: ${email} (id: ${userId})`);
    } else {
      // 确保 email 字段存在
      user = { ...user, email };
      console.log(`[认证] 已有用户登录: ${email}`);
    }

    // 生成 token（包含 userId 和 email）
    const token = jwt.sign(
      { userId: user.id, email: user.email, role: user.role },
      JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.status(200).json({
      success: true,
      message: '登录成功',
      data: {
        user: {
          id: user.id,
          email: user.email,
          name: user.name,
          role: user.role,
          plan: user.plan || 'free'
        },
        token
      }
    });

  } catch (error) {
    console.error('[认证] 登录错误:', error);
    res.status(500).json({ success: false, error: '服务器错误' });
  }
});

// POST /api/auth/register - 用户注册
router.post('/register', (req, res) => {
  try {
    const { email, password, name } = req.body;

    if (!email || !password) {
      return res.status(400).json({
        success: false,
        error: '邮箱和密码不能为空'
      });
    }

    console.log(`[认证] 注册请求: ${email}`);

    // 检查是否已存在
    if (findUserByEmail(email)) {
      return res.status(400).json({
        success: false,
        error: '该邮箱已被注册'
      });
    }

    // 内置账号不能重复注册
    if (BUILTIN_USERS[email]) {
      return res.status(400).json({
        success: false,
        error: '该邮箱已被注册'
      });
    }

    const userId = generateUserId();
    const user = {
      id: userId,
      email,
      name: name || email.split('@')[0],
      role: 'user',
      plan: 'free',
      createdAt: new Date().toISOString()
    };

    const saved = createUser(user);
    if (!saved) {
      return res.status(500).json({ success: false, error: '用户创建失败' });
    }

    console.log(`[认证] 新用户注册: ${email} (id: ${userId})`);

    const token = jwt.sign(
      { userId, email, role: 'user' },
      JWT_SECRET,
      { expiresIn: '7d' }
    );

    res.status(201).json({
      success: true,
      data: {
        user: {
          id: userId,
          email,
          name: user.name,
          role: 'user',
          plan: 'free'
        },
        token
      }
    });

  } catch (error) {
    console.error('[认证] 注册错误:', error);
    res.status(500).json({ success: false, error: '服务器错误' });
  }
});

// GET /api/auth/profile - 获取用户信息
router.get('/profile', (req, res) => {
  try {
    const authHeader = req.headers['authorization'];
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return res.status(401).json({
        success: false,
        error: '未提供认证令牌'
      });
    }

    const token = authHeader.substring(7);
    try {
      const decoded = jwt.verify(token, JWT_SECRET);

      // 从 JSON 文件查找用户
      const user = findUserById(decoded.userId);

      if (user) {
        return res.json({
          success: true,
          data: { user: { ...user, email: decoded.email } }
        });
      }

      // 兼容内置账号
      if (BUILTIN_USERS[decoded.email]) {
        return res.json({
          success: true,
          data: { user: { ...BUILTIN_USERS[decoded.email], email: decoded.email } }
        });
      }

      return res.status(401).json({
        success: false,
        error: '用户不存在'
      });

    } catch (error) {
      return res.status(401).json({
        success: false,
        error: '无效的令牌'
      });
    }

  } catch (error) {
    console.error('[认证] 获取个人资料错误:', error);
    res.status(500).json({ success: false, error: '服务器错误' });
  }
});

// GET /api/auth/test - 测试认证状态
router.get('/test', (req, res) => {
  res.json({
    success: true,
    data: {
      service: 'claw-auth',
      version: '1.0.1-fixed',
      status: 'active',
      mode: '持久化认证（data/users.json）',
      endpoints: [
        'POST /login - 用户登录',
        'POST /register - 用户注册',
        'GET /profile - 令牌验证'
      ]
    }
  });
});

export default router;
